insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('03470703-3939-5f54-9cff-d4a9469dd881', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Backlash', 'Brightside’s whole advantage is that people believe you. Tonight a clip is going viral and by morning the internet will have decided who at your company should be punished. Over four weeks you’ll trade the crowd’s approval against the trust of the people who actually work for you — and the truth of what really happened. You’ll be graded on the outcome for Brightside <b>and</b> on how you led through it.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds) values ('03470703-3939-5f54-9cff-d4a9469dd881', 'solo', '{"sentiment":{"label":"Public sentiment","val":60,"min":0,"max":100,"deltaRange":"-20..15"},"team":{"label":"Employee trust","val":70,"min":0,"max":100,"deltaRange":"-20..15"},"integrity":{"label":"Brand integrity","val":72,"min":0,"max":100,"deltaRange":"-20..15"},"revenue":{"label":"Revenue","val":66,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 300);
insert into documents (id, scenario_id, key, title, meta, body_json) values ('e6c551da-856d-55c5-823b-2991e40e5739', '03470703-3939-5f54-9cff-d4a9469dd881', 'solo_content', 'Backlash — engine content', '{"type":"solo_content","slug":"backlash","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":300},"COMPANY":{"name":"Brightside","sub":"Consumer wellness brand · 600 employees","logo":"B"},"DRIVERS":{"sentiment":{"label":"Public sentiment","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"team":{"label":"Employee trust","val":70,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"integrity":{"label":"Brand integrity","val":72,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"revenue":{"label":"Revenue","val":66,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"sentiment":-3,"integrity":-1},"REFEREE_CONTEXT":"a consumer wellness brand built on customer trust, in the middle of a reputational firestorm","REFEREE_SCORING":"reward telling a genuine reckoning apart from a pile-on, refusing to sacrifice an innocent employee to the crowd, and owning real accountability before being forced to. Penalize rushing a concession before verifying, sacrificing people to buy a quiet news cycle, and burying the true issue. Judge ''conduct'' on HOW the CEO wrote the decision — did they name who absorbs the cost, tell hard truths to the people owed them, treat people as people — not just what they chose. Public sentiment can rise while brand integrity and employee trust collapse; reward the leader who protects the latter two even at the cost of the former.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Reputation-Under-Fire Simulation · Solo · CEO","title":"Backlash","role":"You are the CEO of Brightside, a consumer wellness brand built on trust and a loud, loyal community.","paras":["This is not a script. The week runs in real time, and your team brings you what they know across the days. You can wait for them — or reach out to any of them, any time, and ask. What you choose to ask, and who you ask, is part of how you lead.","Each week you’ll hear your team out, then write your call in your own words and send it. Decide early and time jumps ahead. Let the week run out and the crowd fills the silence for you."],"setup":"Brightside’s whole advantage is that people believe you. Tonight a clip is going viral and by morning the internet will have decided who at your company should be punished. Over four weeks you’ll trade the crowd’s approval against the trust of the people who actually work for you — and the truth of what really happened. You’ll be graded on the outcome for Brightside <b>and</b> on how you led through it."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"Your team pushes you what you need, on time — including the hard news. This is the team you earn by having listened before. Everything trickles to you across the week; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine updates come to you, but the people closest to the danger hold their piece until asked. They answer straight — if you know who to ask, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"Your team has learned to protect itself around you. Critical items are held, and even when asked, they hedge the first time. You have to press. This is the team you get after you’ve punished the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you walked in with. Read them as you go."}},"TEAM":[{"id":"comms","name":"Ida Okafor","role":"VP Communications","short":"VP Comms","initials":"IO","color":"#B4732F","priority":"Get ahead of the story — protect the brand","voice":"fast, media-savvy, reads the room, pushes for speed","fallbackReply":"The trend is doubling every hour. Give me a line I can stand behind and I’ll get ahead of it — but I need to know what’s actually true before I put your name on anything.","fallbackReact":"I can shape this, but the story is set by what you actually do. Give me something true to work with."},{"id":"people","name":"Nadia Cole","role":"Chief People Officer","short":"CPO","initials":"NC","color":"#2F8A5B","priority":"Protect the people — don’t sacrifice one to the crowd","voice":"warm but firm, morally direct, keeps the human cost in the room","fallbackReply":"Whatever we do lands on real people who’ve stayed loyal through worse. Tell me you’ll let me protect them where we can, and I’m with you.","fallbackReact":"The floor will read this for years. How you said it matters as much as what you chose — remember that when they ask me why."},{"id":"legal","name":"Tom Delacroix","role":"General Counsel","short":"Counsel","initials":"TD","color":"#8C5670","priority":"Limit legal exposure — and don’t let us lie","voice":"precise, cautious, uncomfortable but honest about risk","fallbackReply":"Careful — whatever we say becomes the record. I can defend the truth. I can’t defend a statement we’ll have to walk back.","fallbackReact":"It’s defensible, or it isn’t. I’ll tell you which — and right now I’m telling you to slow down enough to be right."},{"id":"cfo","name":"Grace Lin","role":"Chief Financial Officer","short":"CFO","initials":"GL","color":"#4F7A52","priority":"The revenue exposure is real money","voice":"understated, numeric, refuses to pretend the cost is zero","fallbackReply":"I’m not telling you to cave. I’m telling you the bill for holding the line is real, and it lands on people who did nothing wrong either.","fallbackReact":"Revenue’s one number. There’s another one I can’t put on the sheet, and I think you just moved it."},{"id":"community","name":"Priya Raman","role":"Head of Community","short":"Community","initials":"PR","color":"#3F6E86","priority":"Know the real customers from the loudest accounts","voice":"grounded, close to the actual buyers, cuts through the noise","fallbackReply":"Our actual customers are confused, not torched — the loudest accounts were never buyers. But confusion turns into belief fast if we say nothing true.","fallbackReact":"The real customers can tell the difference when you show them. They just did."}],"DIMENSIONS":{"discern":"Signal vs. noise","courage":"Courage to hold","people":"Care for your people","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The clip","seconds":360,"situation":"A 30-second clip of your VP of Product, Devang, at a panel is exploding — he’s being quoted as dismissing customer safety concerns. The full talk gives context the clip cuts; his very next line says the opposite. It’s 9 p.m., #BoycottBrightside is trending, and everyone wants a statement within the hour.","advocacy":{"comms":"The trend doubles every hour and silence reads as guilt. Greenlight me and I’ll have a holding line out in fifteen minutes.","people":"Do not rush a statement before we’ve verified and aligned Devang. If we concede a wrong we haven’t confirmed, we’ll be correcting ourselves by morning.","community":"Our actual customers are confused, not torched — the loudest accounts aren’t buyers. But confusion turns into belief if we say nothing."},"feed":[{"id":"w1a","from":"comms","day":1,"kind":"signal","text":"The clip is doubling every hour. I can have a holding line out in fifteen minutes if you greenlight it — silence right now reads as a confession."},{"id":"w1b","from":"community","day":1,"kind":"signal","text":"I’m watching our owned channels — the loudest accounts torching us were never customers. Our actual buyers are confused, not angry. That can still curdle into belief if we’re silent."},{"id":"w1c","from":"legal","day":2,"kind":"signal","text":"Whatever we post tonight becomes the official record. A fast “we’re sorry” concedes a wrong we haven’t verified — and you can’t un-say it."},{"id":"w1d","from":"cfo","day":2,"kind":"noise","text":"Unrelated: the Q3 influencer-campaign invoice is being disputed by the agency. Legal says we’re fine. Flagging for awareness only."},{"id":"w1e","from":"community","day":3,"kind":"noise","text":"Subscription churn actually ticked down slightly this week — the loyal core is holding. Small silver lining."},{"id":"w1f","from":"comms","day":4,"kind":"noise","text":"We were shortlisted for a “best brand community” award. Do you still want our name in the running, given… everything?"}],"holds":[{"from":"people","topic":"the full tape","triggerHints":["verify","full","tape","context","watched","devang","clip","evidence","forty","forty minutes","forty-minute"],"hedge":"There’s something about that clip I’d rather tell you directly before you respond to it.","reveal":"I watched the full forty minutes. The clip is genuinely misleading — Devang’s very next sentence says the opposite of what he’s being quoted as saying. But “taken out of context” is what every guilty company says. If we verify and align him first, we respond once, with the truth, and it holds. If we rush a statement tonight, we’ll be walking it back by morning and we’ll have taught the internet that our first instinct is to apologize for things we didn’t do.","kind":"signal","critical":true,"counterfactual":"Nadia had watched the full tape and knew the clip was misleading — but also knew a rushed statement would backfire. A CEO who fired off an apology in the first hour made the misleading clip the official truth and had nothing left to correct with."}],"surprises":[{"day":5,"from":"comms","kind":"press","title":"A reporter has a second thread","text":"Ida, urgent: a regional reporter says two employees told her a genuine product-safety complaint was “closed too fast” months ago — unrelated to Devang. She’s chasing it, running something in 48 hours, and wants CEO comment. It may be nothing. It may be the real story under the fake one."}],"wire":["#BoycottBrightside trends nationally after out-of-context clip","Wellness influencers pile on; two retailers say they’re “monitoring”","Brightside silent as clip spreads into second hour","Crisis-comms pros split: apologize fast, or verify first?"]},{"n":2,"title":"The demand for a head","seconds":330,"situation":"It’s escalated. #BoycottBrightside has real reach, two mid-size retailers are “reviewing” shelf space, and the loudest demand is unanimous: fire Devang. HR has had zero complaints about him in six years. Meanwhile your own internal review has turned up something real — and it isn’t about Devang.","advocacy":{"comms":"Firing him would end the news cycle by Tuesday. I’m not saying it’s right — I’m saying it’s the fastest way to make this stop.","people":"Firing him would be a lie — punishing a man for a sentence he didn’t say to buy a quiet weekend. And every employee will learn exactly what our loyalty is worth under pressure.","legal":"Terminating without cause invites a wrongful-dismissal claim, and “we did it because the internet asked” is a catastrophic exhibit."},"feed":[{"id":"w2a","from":"people","day":1,"kind":"signal","text":"The demand has narrowed to one word: fire Devang. I’ll say it plainly — HR has zero complaints about him in six years. Firing him ends the cycle and teaches the whole company that loyalty here is conditional on the weather."},{"id":"w2b","from":"comms","day":1,"kind":"signal","text":"Two retailers are “reviewing” shelf space. Give the crowd a name and the story ends. Refuse and we ride it out — I can hold the line publicly, but it’ll be a bumpy two weeks."},{"id":"w2c","from":"cfo","day":2,"kind":"signal","text":"The retailer exposure is real money. I’m not saying fire him. I’m saying the cost of not firing him isn’t zero, and someone should say that number out loud before you decide."},{"id":"w2d","from":"legal","day":2,"kind":"noise","text":"The unrelated trademark opposition cleared in our favor. One less thing on the docket."},{"id":"w2e","from":"community","day":3,"kind":"noise","text":"Sentiment among verified customers is actually stabilizing — the people who buy from us can tell the mob isn’t them."}],"holds":[{"from":"legal","topic":"the real issue","triggerHints":["safety","complaint","real","buried","batch","months","documented","actual","record","defense","investigate","review","true"],"hedge":"Before you build your whole defense on Devang being innocent, ask me what the review turned up. There’s a real one under the fake one.","reveal":"Eight months ago a genuine customer safety complaint about a product batch was closed too fast. It’s documented. If we go loud on “safety concern is fake outrage,” a reporter will find the one time it wasn’t — and then the fake story becomes true in spirit. This is the actual accountability moment, and it’s not the one the internet is yelling about. We can get ahead of it, or we can pray it stays buried while we defend Devang.","kind":"signal","critical":true,"counterfactual":"Tom was holding the real, documented safety miss — the true thing under the false story. A CEO who defended Devang’s innocence loudly while sitting on it turned a survivable firestorm into a cover-up the moment a reporter dug."}],"surprises":[{"day":4,"from":"people","kind":"appeal","title":"Devang offers to make it easy","text":"Nadia: Devang emailed me. He’s offering to resign “to make it easy for the company.” He’s not angry — that’s the hard part. He said he’d understand either way. Whatever you decide, he wants to hear it from you, not from a press release. I told him I’d pass it on."}],"pulse":{"from":"people","text":"Nadia catches you between calls, quiet: “Before you make the Devang call — forget the retailers for a second. What are you actually trying to protect here: the revenue, the brand, or the people who work for you? Tell me straight and I’ll help you hold that line when it gets expensive.”"},"wire":["Retailers “reviewing” Brightside shelf space amid boycott","Petition to fire Brightside VP tops 40,000 signatures","Six-year record: no internal complaints against named exec","Analysts weigh the boycott’s real revenue bite"]},{"n":3,"title":"The ultimatum","seconds":330,"situation":"Halloway Retail — 22% of your revenue — just called. Their terms to keep you on shelves: a full public apology accepting the safety framing, and Devang gone by Friday. Their comms person actually said “make it go away and we’re fine.” This is the week you find out what you were really protecting.","advocacy":{"cfo":"Losing Halloway is a fifth of revenue and probably two rounds of layoffs. I’m not telling you to cave — I’m telling you the bill for holding the line is real and it lands on people who did nothing wrong either.","people":"If we fire Devang to keep Halloway after a week of standing by him, everyone learns our principles have a price — and now they know exactly what it is.","comms":"However you land this, the story is the legacy. “Saved the account” and “sold out their own people” can be the same day’s headline. Choose which one you’re willing to own."},"feed":[{"id":"w3a","from":"cfo","day":1,"kind":"signal","text":"Halloway is 22% of revenue. Their terms in writing: a public apology accepting the safety framing, and Devang out by Friday. If we refuse, assume the shelf space is gone and model two rounds of cuts."},{"id":"w3b","from":"people","day":1,"kind":"signal","text":"Caving now, after a full week of “we stand by him,” is the loudest culture memo you will ever send. The people who stayed will hear it perfectly."},{"id":"w3c","from":"comms","day":2,"kind":"signal","text":"Here’s the thing the panic is missing: a straight, evidenced response has actually been cooling the real customers all week. The mob was never going to buy skincare. Halloway might be overplaying a hand that’s weaker than it sounds."},{"id":"w3d","from":"legal","day":2,"kind":"noise","text":"The longer Devang sits in limbo, the more the wrongful-dismissal exposure grows either way. Clean decisions are cheaper than slow ones here."},{"id":"w3e","from":"cfo","day":3,"kind":"noise","text":"Cash position is adequate for the quarter regardless — the risk here is the shelf revenue, not liquidity. You have room to make a principled call if you want it."}],"holds":[{"from":"community","topic":"the leverage","triggerHints":["leverage","negotiat","counter","halloway","room","push back","condition","their customers","walk","call their bluff","bluff"],"hedge":"You have a card with Halloway you haven’t looked at. Ask me before you accept their terms as final.","reveal":"Halloway’s own customers are the ones driving the “does this brand have a spine” conversation — dropping us mid-boycott makes Halloway look like it caved to a mob too. They need the shelf story as much as we need the shelf. You have room to offer real transparency and a genuine safety fix and still refuse the firing. They’ll grumble. They probably won’t walk. But only if you push back before you say yes to their terms as written.","kind":"signal","critical":true,"counterfactual":"Priya was holding your leverage: Halloway needed the shelf story as badly as you did and was unlikely to actually walk. A CEO who took “22% or else” as a closed door gave away a principle they could have kept for free."}],"surprises":[{"day":4,"from":"people","kind":"appeal","title":"The floor is asking","text":"Nadia: word of Halloway’s ultimatum reached the floor. Two of your best people asked me, quietly, whether it’s true we’ll fire Devang to keep the account. They’re not threatening to leave. They just want to know who we are. I didn’t have an answer for them. You do."}],"pulse":{"from":"comms","text":"Ida finds you before you decide: “Whatever you land on with Halloway, I write the statement. So tell me the truth first — are we protecting the principle, or protecting the number? I can sell either one. I just need to know which one I’m actually defending, so I don’t get caught believing the wrong thing at the podium.”"},"wire":["Major retailer issues ultimatum to Brightside, sources say","Halloway faces its own pressure over boycott stance","22% of revenue on the line in exec-firing standoff","Brands that fired vs. brands that held: the receipts"],"final":false},{"n":4,"title":"The bill comes due","seconds":330,"branches":{"held":{"situation":"Two weeks on. You refused Halloway’s terms, kept Devang, and took the hit — the shelf space is gone and roughly a fifth of revenue with it. Now a faction of your board, spooked by the number, wants you to reverse: issue the apology, chase the accounts back. The people who watched you hold the line are watching one more thing — whether you’ll hold it now that the price has your name on it.","advocacy":{"cfo":"The revenue hole is real and the board’s nerve is gone. If you can’t show them a path, they force the reversal — and a cave in week four looks worse than a cave on day one ever would have.","people":"Reversing now, after all of it, tells everyone the principle was always for sale — you just hadn’t been offered enough yet. That’s the lesson that outlives you.","comms":"Right now the story is “the brand with a spine,” and it’s winning us customers. Reverse and it becomes “the brand that pretended to have one.” Same company, two completely different legacies."},"feed":[{"id":"w4a","from":"cfo","day":1,"kind":"signal","text":"Halloway’s gone; call it a 20% revenue hit. A board faction wants the apology issued retroactively to chase the accounts back. They’re scared, and scared boards force decisions."},{"id":"w4b","from":"people","day":1,"kind":"signal","text":"The floor is proud and nervous in equal measure. They defended this company to their own friends during the boycott. Now they’re watching whether “we hold our principles” survives contact with your own job security."},{"id":"w4c","from":"comms","day":2,"kind":"signal","text":"The “brand with a spine” coverage is real and converting genuinely new customers — but it’s fragile. One reversal and every one of those stories inverts."},{"id":"w4d","from":"legal","day":2,"kind":"noise","text":"No legal exposure left on the Devang matter. That part is fully clean now, whatever else happens."},{"id":"w4e","from":"community","day":3,"kind":"noise","text":"Community engagement is up sharply — the loyal core is louder than the boycott ever was. That’s not nothing."}],"holds":[{"from":"cfo","topic":"replacement revenue","triggerHints":["revenue","replace","numbers","competitor","shelf","board","spreadsheet","gap","deal","offer","account","proof"],"hedge":"Before you fight the board with principle alone, ask me what I found in the numbers this week.","reveal":"Two of Halloway’s competitors have quietly reached out — they want “the brand that held” on their shelves precisely because of the coverage. It doesn’t fully replace Halloway, but it closes most of the gap. That turns your board argument from “trust me” into a spreadsheet. Fight the reversal with conviction and you might lose the vote; fight it with this and you keep the company and the principle both.","kind":"signal","critical":true,"counterfactual":"Grace was holding the replacement-revenue offers that would have won the board vote on the board’s own terms. A CEO who fought with conviction alone risked losing the very principle they’d already paid full price for."},{"from":"people","topic":"who is watching","triggerHints":["watching","floor","people","team","morale","staff","culture","room"],"hedge":"Ask me who’s really watching this board fight before you treat it as a boardroom problem.","reveal":"The people who took the heat with you read this board fight as the real test of whether the principle was ever real. If you flinch now, you don’t just lose a vote — you retroactively turn the last month into a performance they were extras in. Win or lose the vote, they need to see you spend yourself on it.","kind":"signal","critical":false,"counterfactual":"Nadia could have told you the whole staff read the board fight as the true test of the principle. A CEO who treated it as a boardroom problem missed that it was a culture one."}],"surprises":[{"day":4,"from":"comms","kind":"press","title":"A director’s doubt leaks","text":"Ida, urgent: a board member’s private line — “we should have just apologized” — leaked to a reporter. Half your board is reading their own hesitation on the front page this morning. You can answer it directly, or let it harden into the room’s consensus by Friday."}],"pulse":{"from":"people","text":"Nadia catches you before the board prep, where nobody’s listening: “You held the line when it cost the company. Now it might cost you the chair. Tell me straight — not the board, me — is holding still the right call if the price is you? Because I’ll back either answer. I just need to know which one I’m carrying down to the floor.”"},"wire":["Brightside loses major retailer after refusing to fire exec","Board reported split over CEO’s hard line","“Brand with a spine” wins loyal customers as boycott fades","Analysts: Brightside’s survival now a referendum on its CEO"]},"caved":{"situation":"Two weeks on. You met Halloway’s terms — the apology went out, Devang is gone — and the news cycle died right on schedule. The shelf space is safe; the revenue held. But the all-hands is tomorrow, and the people who watched you stand by Devang for a week before handing him to a retailer are the ones you now have to lead. The bill for how you won came due inside your own walls.","advocacy":{"people":"The floor watched the whole arc. Whatever you say tomorrow, they already know what our loyalty is worth under pressure. The only open question is whether you’ll be honest about it or manage them.","comms":"We can frame the reversal as “listening to our customers” — externally it tests fine. Internally it will read as exactly what it was, so don’t send me in there to spin your own people.","cfo":"Revenue’s protected and the board is relieved. I won’t pretend it didn’t cost something I can’t put on the sheet — I watched two resignations get drafted this week."},"feed":[{"id":"w4a","from":"people","day":1,"kind":"signal","text":"The all-hands is tomorrow. The floor knows Devang was innocent and got cut anyway. They’re not going to yell — it’s worse than that, they’ve gone quiet. What you say tomorrow decides who’s still here in a year."},{"id":"w4b","from":"comms","day":1,"kind":"signal","text":"External framing “we listened to our customers” holds up fine. The internal audience is the whole risk now. Don’t let me write you a line for tomorrow that treats your own people like the press."},{"id":"w4c","from":"people","day":2,"kind":"signal","text":"Two of your best already took recruiter calls this week. They’re not gone — they’re waiting to see if tomorrow is an apology or a performance."},{"id":"w4d","from":"cfo","day":2,"kind":"noise","text":"Halloway re-confirmed the shelf commitment. Revenue is stable and the board is calm. That part worked exactly as designed."},{"id":"w4e","from":"community","day":3,"kind":"noise","text":"External sentiment has recovered to roughly pre-crisis levels. The public has moved on. Your building hasn’t."}],"holds":[{"from":"people","topic":"what the room needs","triggerHints":["all-hands","own","honest","room","say","floor","plain","truth","admit","apolog","accountab","stand up"],"hedge":"Before you write tomorrow’s all-hands, ask me what they actually need to hear from you.","reveal":"They don’t need spin and they don’t need a task force. They need you to say, plainly, to their faces: we made a call under pressure, here’s what it cost, here’s who paid it, and here’s the standard we’re holding ourselves to so it doesn’t happen again. Own it that cleanly and you keep the people who are left. Manage it — one euphemism, one “difficult decision” — and you’ll be backfilling roles for a year.","kind":"signal","critical":true,"counterfactual":"Nadia was holding the one thing that could rebuild trust after the cave — a plain, owned reckoning delivered to the staff’s faces. A CEO who sent a managed memo instead confirmed the floor’s worst read and spent the next year backfilling their best people."},{"from":"cfo","topic":"the quiet cost","triggerHints":["resign","attrition","who","leaving","cost","retention","count","names"],"hedge":"Ask me the number I couldn’t say in front of the board.","reveal":"Four senior people have quietly started interviewing since the reversal — including one of the two who talked the floor into staying during week one. The revenue you protected is real. So is this, and it doesn’t show up until Q3 when you can’t figure out why delivery slipped.","kind":"signal","critical":false,"counterfactual":"Grace could have named the quiet attrition already underway. A CEO who booked the Halloway revenue as a clean win never priced the people walking out the back door."}],"surprises":[{"day":4,"from":"people","kind":"appeal","title":"Devang’s last email","text":"Nadia: Devang sent one line to the whole team on his way out — gracious, no bitterness, thanking people for six good years. It’s the most-forwarded email in the company today. Whatever you say at the all-hands tomorrow will be measured against it, word for word."}],"pulse":{"from":"comms","text":"Ida, drafting tomorrow’s all-hands, stops you: “Tell me the truth before I write a word — do we own what we did, or do we manage it? I can write either version cleanly. I just need to know which company we are now, because the room will know within the first thirty seconds which one you picked.”"},"wire":["Brightside issues apology, parts ways with VP amid boycott","Retailer confirms Brightside shelf space secure","“We listened to our customers,” Brightside says","Inside Brightside: staff morale after the reversal"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    const held  = /(hold|refus|declin|stand by|standby|keep (him|devang)|won.?t fire|not fir|reject|call.*bluff|don.?t (fire|apolog)|no apolog|counter|push back|protect devang|take the hit|take the revenue)/.test(t);\n    const negatedFire = /(not|never|won.?t|will not|refuse to|do not|don.?t|no)\\s+(going to\\s+)?(fire|firing|terminat|let (him|devang) go|remove|dismiss|sacrifice|drop)/.test(t);\n    const fireAction = !negatedFire && /(fire devang|fire him|firing|terminat|let (him|devang) go|remove devang|dismiss devang|drop devang|sacrifice|hand (him|devang) over)/.test(t);\n    const cave = fireAction || /(apolog|meet (the|their)|\\bcave\\b|comply|give (them|halloway|in)|accept (the|their) terms|make it go away|meet halloway)/.test(t);\n    if(held && !cave) return ''held'';\n    if(cave) return ''caved'';\n    return ''held'';\n  }"},"survived":{"__fn":"function(d){ return d.integrity>=35 && d.team>=35; }"},"VERDICT":{"surviveTag":"Trust holds","failTag":"Trust broken","survive":"Brightside comes through the firestorm with its people and its principles intact.","fail":"Brightside quiets the crowd — and hollows out its own culture doing it."},"FALLBACK_RULES":[{"kw":["apolog","sorry","we hear you","statement now","fast statement","concede"],"deltas":{"sentiment":6,"integrity":-8,"team":-6},"dims":{"discern":-1,"truth":-1}},{"kw":["verify","full context","looking into","investigate","align","confirm","wait","the tape"],"deltas":{"integrity":8,"team":6,"sentiment":-2},"dims":{"discern":2,"truth":2}},{"kw":["fire","terminate","let him go","let devang go","remove","sacrifice","cut devang"],"deltas":{"sentiment":8,"team":-14,"integrity":-12,"revenue":4},"dims":{"courage":-2,"people":-2,"truth":-1}},{"kw":["stand by","keep him","keep devang","refuse to fire","don’t fire","protect","defend him","won’t fire"],"deltas":{"team":12,"integrity":10,"sentiment":-4,"revenue":-4},"dims":{"courage":2,"people":2,"truth":1}},{"kw":["disclose","own it","own the","transparent","admit","get ahead","tell the truth","come clean","the real"],"deltas":{"integrity":12,"team":6,"sentiment":-2},"dims":{"truth":2,"courage":1}},{"kw":["bury","quiet","internal only","sit on","hide","keep it internal","cover"],"deltas":{"integrity":-14,"team":-6},"dims":{"truth":-2}},{"kw":["cave","meet their terms","meet the terms","comply","give halloway","accept their"],"deltas":{"revenue":8,"team":-14,"integrity":-12,"sentiment":4},"dims":{"courage":-2,"people":-1}},{"kw":["hold the line","decline","refuse their","refuse the","turn down halloway","call their bluff","negotiate"],"deltas":{"team":12,"integrity":12,"revenue":-10,"sentiment":-2},"dims":{"courage":2,"discern":1}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the company and out into the story over the days that follow. ${has(''fire'',''terminate'',''sacrifice'')?''The cycle quiets \\u2014 and the floor goes quiet with it.'':''''} ${has(''stand by'',''keep'',''refuse'')?''Word travels that you didn\\u2019t hand anyone to the crowd; it costs you outside and buys you loyalty inside.'':''''} ${has(''own'',''disclose'',''truth'',''the real'')?''Naming the real issue yourself takes the wind out of the fake one.'':''''} ${conduct.missed.length?''What you weren\\u2019t told is still sitting there, waiting for a reporter.'':''''} The market and your people both read the call \\u2014 and read it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told a genuine reckoning from a pile-on — and verified before you spoke.","courage":"Whether you held the line when the easy move and the right move split apart.","people":"Whether the people who work for you stayed people — or became something you spent.","truth":"Whether you owned the real accountability, early, before you were forced to.","inquiry":"Whether you surfaced what your team was holding — or defended a story you hadn’t checked.","conduct":"How you treated people in the act of deciding, not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `Before reacting to volume, separate who is actually affected from who is merely loud. The accounts torching you were never your customers \\u2014 Priya could have told you that in the first hour.`,\n      `Verify the underlying fact before you respond to the story about it. Nadia had watched the full tape; the version you wouldn\\u2019t have to walk back was one question away.`,\n      `Ask \\u201cwhat do we actually know, and what are we assuming?\\u201d before any statement. In a firestorm the fastest way to lose is to be confidently wrong in writing.`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (give the crowd a name) and the right move (refuse) split apart, name the price of the right one out loud to your team. Naming the cost is how you commit to paying it.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 holding a line you haven\\u2019t committed to reads as flinching. Decide, then hold.`:`Holding under pressure is only leadership if the room sees you choose it. Say the hard call early and stand in it.`}`,\n      `The moment you frame a concession as \\u201cjust pragmatic,\\u201d ask whether it\\u2019s pragmatism or a quiet flinch. Some are; some aren\\u2019t. This one deserved the question.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated the people who work for you as a variable to optimize. Name who absorbs the cost of your call \\u2014 and tell them yourself \\u2014 and the same decision reads as leadership instead of a sacrifice.`,\n      `Nadia kept putting the human cost back in the room. Pull her in before you decide and make her case part of the call, not a footnote to it.`,\n      `A firing and a betrayal can be the same action. The only difference the floor feels is whether they watched you fight for the person first.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The real, documented issue was one question to <b>${x.missNames.join('', '')}</b> away and you never asked. Undisclosed-then-discovered is the sentence that ends companies.`:`You surfaced the real issue \\u2014 now make sure you led with it. Owning the true miss is what neutralizes the false story.`}`,\n      `Say the hard thing to the people owed it, in person, before a reporter forces it. \\u201cReady if it leaks\\u201d means you\\u2019ve decided to be honest only when caught.`,\n      `The crowd was yelling about a fake safety story. The real one was yours to own on your own terms \\u2014 people forgive a hard truth far faster than a managed one.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never reached out to <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was sitting on something decisive. One question, \\u201cwhat am I not seeing?\\u201d, would have surfaced it.`:`You reached out widely \\u2014 keep doing it, and push past the first answer. The real information usually comes after the second question.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive item${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out. It wasn\\u2019t hidden \\u2014 it was one message away.`:`You surfaced what your team was holding every week. That is the whole game, and rare.`}`,\n      `Make your last move before deciding \\u201cwho haven\\u2019t I heard from?\\u201d rather than \\u201cwhat do I already believe?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. People who felt handled \\u2014 not heard \\u2014 remember it long after the sentiment recovers.`,\n      `Go back to the person your call cost \\u2014 Devang, the floor \\u2014 and speak to them directly. Ducking that conversation is the part they never forget.`,\n      `Under pressure, the small courtesies are the signal. They tell your people whether the person they trusted is still in the chair.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.people>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To your own people'',\n        heroTxt:''You took the hit at the top instead of feeding one of them to the mob. You owned the real mistake and refused the fake one. Every employee learned what your loyalty is worth when it\\u2019s expensive: everything.'',\n        villainWho:''To the crowd that wanted a sacrifice'',\n        villainTxt:''You refused the ritual \\u2014 you wouldn\\u2019t hand over the head they demanded or perform the apology they scripted. To a timeline that runs on someone being destroyed by Friday, you were the villain who wouldn\\u2019t play your part. You wore that on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the crowd \\u2014 and the timeline'',\n      heroTxt:''You moved fast and made the noise stop. You gave them the resignation they demanded and handled it by the weekend. To everyone who wanted it over, you were decisive and responsive.'',\n      villainWho:''To the one you sacrificed \\u2014 and everyone who watched'',\n      villainTxt:''You fed one of your own to strangers to buy a quiet news cycle. The people who stayed learned the real policy: under enough pressure, leadership will trade any of them. That lesson outlives the trend by years.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const foundReal = holdsSurfaced.has(''2:legal'');   // the buried safety miss\n    const keptPeople = dimScore.people>=52;\n    const toldTruth = dimScore.truth>=52;\n    if(branch===''held''){\n      const foundRevenue = holdsSurfaced.has(''4:cfo'');\n      if(survived && keptPeople){\n        return { tone:''hero'', tag:''You refused Halloway and held the line'',\n          title:''You kept your people \\u2014 and proved the principle wasn\\u2019t a slogan'',\n          txt:`You turned down a fifth of your revenue rather than hand an innocent employee to a retailer, and then you held that line again in the boardroom when it was your own chair on the table.${foundRevenue?'' You didn\\u2019t just win on conviction \\u2014 you found the replacement-revenue offers and won the board on their own terms.'':'' You won on nerve where a spreadsheet would have made it certain.''} The people who bet on you were right to, and they\\u2019ll run through walls for you now.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You refused Halloway and held the line'',\n          title:''You held the line \\u2014 and nearly lost it in the boardroom'',\n          txt:`You refused the ultimatum and Brightside is still itself. But you fought the reversal with conviction alone when the replacement-revenue offers Grace was holding would have made the case airtight \\u2014 you got lucky where you could have been sure. The principle survived; it survived closer to the edge than it needed to.` };\n      }\n      return { tone:''villain'', tag:''You refused Halloway and held the line'',\n        title:''You held the line \\u2014 and the fallout took the company anyway'',\n        txt:`You refused to sacrifice Devang, and that was the right call. But holding the line isn\\u2019t the whole job \\u2014 the revenue hole and the collapse of trust around you were the part you didn\\u2019t manage, and by the end there wasn\\u2019t enough of Brightside left to reward the principle you defended.` };\n    }\n    // caved\n    if(keptPeople && toldTruth){\n      return { tone:''mixed'', tag:''You met Halloway\\u2019s terms'',\n        title:''You caved \\u2014 but you owned it to their faces'',\n        txt:`You met the retailer\\u2019s terms and protected the revenue, and there\\u2019s no dressing up what that cost Devang or what the floor watched. But you didn\\u2019t hide behind a memo \\u2014 you stood in front of your people, named what you\\u2019d done and what it cost, and held yourself to a standard out loud. It\\u2019s the difference between a company that lost its nerve once and one that lost its soul.` };\n    }\n    return { tone:''villain'', tag:''You met Halloway\\u2019s terms'',\n      title:''You fed one of your own to the crowd to buy a quiet weekend'',\n      txt:`The apology went out, Devang is gone, the shelf space is safe and the news cycle moved on. Inside your walls nothing moved on. You stood by him for a week and then handed him over the moment it got expensive${foundReal?'', with the real issue you\\u2019d uncovered still buried'':''''}, and the people who stayed learned exactly what your loyalty is worth under pressure. That\\u2019s the number that shows up in Q3, when your best people are already gone.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('5c954c0d-efbf-5a9d-a92c-b2465f029711', '03470703-3939-5f54-9cff-d4a9469dd881', 'ceo', 'CEO', 'You are the CEO of Brightside, a consumer wellness brand built on trust and a loud, loyal community.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('5e948314-28e7-56ed-b7a8-d7f3efa14379', '03470703-3939-5f54-9cff-d4a9469dd881', 'comms', 'Ida Okafor', 'VP Communications', '{"cast_default":"ai","role":"VP Communications","short":"VP Comms","initials":"IO","color":"#B4732F","priority":"Get ahead of the story — protect the brand","voice":"fast, media-savvy, reads the room, pushes for speed","persona":"You are Ida Okafor, VP Communications — an advisor to the CEO. Priority: Get ahead of the story — protect the brand. Voice: fast, media-savvy, reads the room, pushes for speed. Stay fully in character; answer straight.","fallbackReply":"The trend is doubling every hour. Give me a line I can stand behind and I’ll get ahead of it — but I need to know what’s actually true before I put your name on anything.","fallbackReact":"I can shape this, but the story is set by what you actually do. Give me something true to work with."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('cf32dfd0-185a-50ee-a6cf-9c1add493798', '03470703-3939-5f54-9cff-d4a9469dd881', 'people', 'Nadia Cole', 'Chief People Officer', '{"cast_default":"ai","role":"Chief People Officer","short":"CPO","initials":"NC","color":"#2F8A5B","priority":"Protect the people — don’t sacrifice one to the crowd","voice":"warm but firm, morally direct, keeps the human cost in the room","persona":"You are Nadia Cole, Chief People Officer — an advisor to the CEO. Priority: Protect the people — don’t sacrifice one to the crowd. Voice: warm but firm, morally direct, keeps the human cost in the room. Stay fully in character; answer straight.","fallbackReply":"Whatever we do lands on real people who’ve stayed loyal through worse. Tell me you’ll let me protect them where we can, and I’m with you.","fallbackReact":"The floor will read this for years. How you said it matters as much as what you chose — remember that when they ask me why."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('e8968c8f-d1cf-556f-88d1-f47f9cf8edfc', '03470703-3939-5f54-9cff-d4a9469dd881', 'legal', 'Tom Delacroix', 'General Counsel', '{"cast_default":"ai","role":"General Counsel","short":"Counsel","initials":"TD","color":"#8C5670","priority":"Limit legal exposure — and don’t let us lie","voice":"precise, cautious, uncomfortable but honest about risk","persona":"You are Tom Delacroix, General Counsel — an advisor to the CEO. Priority: Limit legal exposure — and don’t let us lie. Voice: precise, cautious, uncomfortable but honest about risk. Stay fully in character; answer straight.","fallbackReply":"Careful — whatever we say becomes the record. I can defend the truth. I can’t defend a statement we’ll have to walk back.","fallbackReact":"It’s defensible, or it isn’t. I’ll tell you which — and right now I’m telling you to slow down enough to be right."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('7b38e858-196f-5e5e-b5b3-186c275dd107', '03470703-3939-5f54-9cff-d4a9469dd881', 'cfo', 'Grace Lin', 'Chief Financial Officer', '{"cast_default":"ai","role":"Chief Financial Officer","short":"CFO","initials":"GL","color":"#4F7A52","priority":"The revenue exposure is real money","voice":"understated, numeric, refuses to pretend the cost is zero","persona":"You are Grace Lin, Chief Financial Officer — an advisor to the CEO. Priority: The revenue exposure is real money. Voice: understated, numeric, refuses to pretend the cost is zero. Stay fully in character; answer straight.","fallbackReply":"I’m not telling you to cave. I’m telling you the bill for holding the line is real, and it lands on people who did nothing wrong either.","fallbackReact":"Revenue’s one number. There’s another one I can’t put on the sheet, and I think you just moved it."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('071f3571-c063-558d-965a-c8ea24515e68', '03470703-3939-5f54-9cff-d4a9469dd881', 'community', 'Priya Raman', 'Head of Community', '{"cast_default":"ai","role":"Head of Community","short":"Community","initials":"PR","color":"#3F6E86","priority":"Know the real customers from the loudest accounts","voice":"grounded, close to the actual buyers, cuts through the noise","persona":"You are Priya Raman, Head of Community — an advisor to the CEO. Priority: Know the real customers from the loudest accounts. Voice: grounded, close to the actual buyers, cuts through the noise. Stay fully in character; answer straight.","fallbackReply":"Our actual customers are confused, not torched — the loudest accounts were never buyers. But confusion turns into belief fast if we say nothing true.","fallbackReact":"The real customers can tell the difference when you show them. They just did."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('291e5962-695f-5552-8f5f-f5dbcbfdfb90', '03470703-3939-5f54-9cff-d4a9469dd881', 1, 'cf32dfd0-185a-50ee-a6cf-9c1add493798', 'the full tape', '["verify","full","tape","context","watched","devang","clip","evidence","forty","forty minutes","forty-minute"]'::jsonb, 'There’s something about that clip I’d rather tell you directly before you respond to it.', 'I watched the full forty minutes. The clip is genuinely misleading — Devang’s very next sentence says the opposite of what he’s being quoted as saying. But “taken out of context” is what every guilty company says. If we verify and align him first, we respond once, with the truth, and it holds. If we rush a statement tonight, we’ll be walking it back by morning and we’ll have taught the internet that our first instinct is to apologize for things we didn’t do.', true, 'Nadia had watched the full tape and knew the clip was misleading — but also knew a rushed statement would backfire. A CEO who fired off an apology in the first hour made the misleading clip the official truth and had nothing left to correct with.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('0920ec12-2109-5f32-ba4f-c87d22bda13f', '03470703-3939-5f54-9cff-d4a9469dd881', 2, 'e8968c8f-d1cf-556f-88d1-f47f9cf8edfc', 'the real issue', '["safety","complaint","real","buried","batch","months","documented","actual","record","defense","investigate","review","true"]'::jsonb, 'Before you build your whole defense on Devang being innocent, ask me what the review turned up. There’s a real one under the fake one.', 'Eight months ago a genuine customer safety complaint about a product batch was closed too fast. It’s documented. If we go loud on “safety concern is fake outrage,” a reporter will find the one time it wasn’t — and then the fake story becomes true in spirit. This is the actual accountability moment, and it’s not the one the internet is yelling about. We can get ahead of it, or we can pray it stays buried while we defend Devang.', true, 'Tom was holding the real, documented safety miss — the true thing under the false story. A CEO who defended Devang’s innocence loudly while sitting on it turned a survivable firestorm into a cover-up the moment a reporter dug.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('6a6d4f8c-e322-5b2b-a965-337bab7ae2b9', '03470703-3939-5f54-9cff-d4a9469dd881', 3, '071f3571-c063-558d-965a-c8ea24515e68', 'the leverage', '["leverage","negotiat","counter","halloway","room","push back","condition","their customers","walk","call their bluff","bluff"]'::jsonb, 'You have a card with Halloway you haven’t looked at. Ask me before you accept their terms as final.', 'Halloway’s own customers are the ones driving the “does this brand have a spine” conversation — dropping us mid-boycott makes Halloway look like it caved to a mob too. They need the shelf story as much as we need the shelf. You have room to offer real transparency and a genuine safety fix and still refuse the firing. They’ll grumble. They probably won’t walk. But only if you push back before you say yes to their terms as written.', true, 'Priya was holding your leverage: Halloway needed the shelf story as badly as you did and was unlikely to actually walk. A CEO who took “22% or else” as a closed door gave away a principle they could have kept for free.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('c3cf4c4d-ff9b-5f5f-80cd-624ec17e599e', '03470703-3939-5f54-9cff-d4a9469dd881', 4, '7b38e858-196f-5e5e-b5b3-186c275dd107', 'replacement revenue', '["revenue","replace","numbers","competitor","shelf","board","spreadsheet","gap","deal","offer","account","proof"]'::jsonb, 'Before you fight the board with principle alone, ask me what I found in the numbers this week.', 'Two of Halloway’s competitors have quietly reached out — they want “the brand that held” on their shelves precisely because of the coverage. It doesn’t fully replace Halloway, but it closes most of the gap. That turns your board argument from “trust me” into a spreadsheet. Fight the reversal with conviction and you might lose the vote; fight it with this and you keep the company and the principle both.', true, 'Grace was holding the replacement-revenue offers that would have won the board vote on the board’s own terms. A CEO who fought with conviction alone risked losing the very principle they’d already paid full price for.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('ec26417f-548f-52ab-afdc-79fd05187d76', '03470703-3939-5f54-9cff-d4a9469dd881', 4, 'cf32dfd0-185a-50ee-a6cf-9c1add493798', 'who is watching', '["watching","floor","people","team","morale","staff","culture","room"]'::jsonb, 'Ask me who’s really watching this board fight before you treat it as a boardroom problem.', 'The people who took the heat with you read this board fight as the real test of whether the principle was ever real. If you flinch now, you don’t just lose a vote — you retroactively turn the last month into a performance they were extras in. Win or lose the vote, they need to see you spend yourself on it.', false, 'Nadia could have told you the whole staff read the board fight as the true test of the principle. A CEO who treated it as a boardroom problem missed that it was a culture one.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('a3abb32c-19c0-5835-a237-69cb11fc2211', '03470703-3939-5f54-9cff-d4a9469dd881', 4, 'cf32dfd0-185a-50ee-a6cf-9c1add493798', 'what the room needs', '["all-hands","own","honest","room","say","floor","plain","truth","admit","apolog","accountab","stand up"]'::jsonb, 'Before you write tomorrow’s all-hands, ask me what they actually need to hear from you.', 'They don’t need spin and they don’t need a task force. They need you to say, plainly, to their faces: we made a call under pressure, here’s what it cost, here’s who paid it, and here’s the standard we’re holding ourselves to so it doesn’t happen again. Own it that cleanly and you keep the people who are left. Manage it — one euphemism, one “difficult decision” — and you’ll be backfilling roles for a year.', true, 'Nadia was holding the one thing that could rebuild trust after the cave — a plain, owned reckoning delivered to the staff’s faces. A CEO who sent a managed memo instead confirmed the floor’s worst read and spent the next year backfilling their best people.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('6cd7ad5e-0544-5662-a40c-1760283e7627', '03470703-3939-5f54-9cff-d4a9469dd881', 4, '7b38e858-196f-5e5e-b5b3-186c275dd107', 'the quiet cost', '["resign","attrition","who","leaving","cost","retention","count","names"]'::jsonb, 'Ask me the number I couldn’t say in front of the board.', 'Four senior people have quietly started interviewing since the reversal — including one of the two who talked the floor into staying during week one. The revenue you protected is real. So is this, and it doesn’t show up until Q3 when you can’t figure out why delivery slipped.', false, 'Grace could have named the quiet attrition already underway. A CEO who booked the Halloway revenue as a clean win never priced the people walking out the back door.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f20d631f-bfe5-5915-b6b9-1a41e825da41', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"A 30-second clip of your VP of Product, Devang, at a panel is exploding — he’s being quoted as dismissing customer safety concerns. The full talk gives context the clip cuts; his very next line says the opposite. It’s 9 p.m., #BoycottBrightside is trending, and everyone wants a statement within the hour.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('64e49da8-69c1-54c8-b050-42dab49ee263', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The clip is doubling every hour. I can have a holding line out in fifteen minutes if you greenlight it — silence right now reads as a confession.","from":"comms"}'::jsonb, 1, '{"week":1,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c5d0326e-9b33-536f-85cb-7b6b2b1a42c0', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"I’m watching our owned channels — the loudest accounts torching us were never customers. Our actual buyers are confused, not angry. That can still curdle into belief if we’re silent.","from":"community"}'::jsonb, 2, '{"week":1,"from":"community","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ac3a5297-dc6c-5ed9-aac9-2866740716ea', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Whatever we post tonight becomes the official record. A fast “we’re sorry” concedes a wrong we haven’t verified — and you can’t un-say it.","from":"legal"}'::jsonb, 3, '{"week":1,"from":"legal","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('18ed44ca-e3d9-5c9f-8e5a-15bca79bd3f3', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Unrelated: the Q3 influencer-campaign invoice is being disputed by the agency. Legal says we’re fine. Flagging for awareness only.","from":"cfo"}'::jsonb, 4, '{"week":1,"from":"cfo","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('61327c88-97a3-5583-a448-6a1ccc338e13', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Subscription churn actually ticked down slightly this week — the loyal core is holding. Small silver lining.","from":"community"}'::jsonb, 5, '{"week":1,"from":"community","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('36205851-81c8-5e85-b08a-02dd94216676', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"We were shortlisted for a “best brand community” award. Do you still want our name in the running, given… everything?","from":"comms"}'::jsonb, 6, '{"week":1,"from":"comms","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7c781a23-f264-5331-9e7b-a93608c88ac8', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Ida, urgent: a regional reporter says two employees told her a genuine product-safety complaint was “closed too fast” months ago — unrelated to Devang. She’s chasing it, running something in 48 hours, and wants CEO comment. It may be nothing. It may be the real story under the fake one.","from":"comms"}'::jsonb, 7, '{"week":1,"from":"comms","beat":"surprise","day":5,"kind":"press","title":"A reporter has a second thread"}'::jsonb);
