insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3c0f79da-1eb7-515e-af33-a146797de374', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Crisis-comms pros split: apologize fast, or verify first?","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2550582c-2c94-5bea-bd0b-d37d9704d45f', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"It’s escalated. #BoycottBrightside has real reach, two mid-size retailers are “reviewing” shelf space, and the loudest demand is unanimous: fire Devang. HR has had zero complaints about him in six years. Meanwhile your own internal review has turned up something real — and it isn’t about Devang.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2d314ef0-da47-5a56-8ad1-5f9c549e7ee6', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The demand has narrowed to one word: fire Devang. I’ll say it plainly — HR has zero complaints about him in six years. Firing him ends the cycle and teaches the whole company that loyalty here is conditional on the weather.","from":"people"}'::jsonb, 13, '{"week":2,"from":"people","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a2922e8d-0bfe-5c7e-95cf-d99a96cce87f', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Two retailers are “reviewing” shelf space. Give the crowd a name and the story ends. Refuse and we ride it out — I can hold the line publicly, but it’ll be a bumpy two weeks.","from":"comms"}'::jsonb, 14, '{"week":2,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bc5ec46d-00f3-5be9-9158-a8181387466c', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The retailer exposure is real money. I’m not saying fire him. I’m saying the cost of not firing him isn’t zero, and someone should say that number out loud before you decide.","from":"cfo"}'::jsonb, 15, '{"week":2,"from":"cfo","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6cf3abee-3890-5d25-9cad-a4fabd5ecf40', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The unrelated trademark opposition cleared in our favor. One less thing on the docket.","from":"legal"}'::jsonb, 16, '{"week":2,"from":"legal","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bb3256ae-e60c-50e4-9c9e-8f31c71994e0', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Sentiment among verified customers is actually stabilizing — the people who buy from us can tell the mob isn’t them.","from":"community"}'::jsonb, 17, '{"week":2,"from":"community","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('92e75555-be21-56d9-b7e7-cd68b45747a4', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Nadia: Devang emailed me. He’s offering to resign “to make it easy for the company.” He’s not angry — that’s the hard part. He said he’d understand either way. Whatever you decide, he wants to hear it from you, not from a press release. I told him I’d pass it on.","from":"people"}'::jsonb, 18, '{"week":2,"from":"people","beat":"surprise","day":4,"kind":"appeal","title":"Devang offers to make it easy"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('561eb95f-0d90-5632-926c-4e19d3fd3a21', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Nadia catches you between calls, quiet: “Before you make the Devang call — forget the retailers for a second. What are you actually trying to protect here: the revenue, the brand, or the people who work for you? Tell me straight and I’ll help you hold that line when it gets expensive.”","from":"people"}'::jsonb, 19, '{"week":2,"from":"people","beat":"pulse"}'::jsonb);
