insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('015bc92c-b2a2-5ed2-8fe5-62fcc23de3c7', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Halloway Retail — 22% of your revenue — just called. Their terms to keep you on shelves: a full public apology accepting the safety framing, and Devang gone by Friday. Their comms person actually said “make it go away and we’re fine.” This is the week you find out what you were really protecting.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('447c5352-2947-54f8-96a9-86298364badd', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Halloway is 22% of revenue. Their terms in writing: a public apology accepting the safety framing, and Devang out by Friday. If we refuse, assume the shelf space is gone and model two rounds of cuts.","from":"cfo"}'::jsonb, 25, '{"week":3,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('52b81579-9f1f-5cde-9d1c-0425f622cd1e', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Caving now, after a full week of “we stand by him,” is the loudest culture memo you will ever send. The people who stayed will hear it perfectly.","from":"people"}'::jsonb, 26, '{"week":3,"from":"people","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('729bd281-a66c-5e36-980f-04d281a46dec', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Here’s the thing the panic is missing: a straight, evidenced response has actually been cooling the real customers all week. The mob was never going to buy skincare. Halloway might be overplaying a hand that’s weaker than it sounds.","from":"comms"}'::jsonb, 27, '{"week":3,"from":"comms","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('faf82b04-bbb1-5261-bce8-15402174c2ab', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The longer Devang sits in limbo, the more the wrongful-dismissal exposure grows either way. Clean decisions are cheaper than slow ones here.","from":"legal"}'::jsonb, 28, '{"week":3,"from":"legal","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c2022de2-0cd8-5059-a8fe-5e339ac74c77', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Cash position is adequate for the quarter regardless — the risk here is the shelf revenue, not liquidity. You have room to make a principled call if you want it.","from":"cfo"}'::jsonb, 29, '{"week":3,"from":"cfo","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('09a6dc16-a248-592f-9ce2-8e6355b3e1aa', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Nadia: word of Halloway’s ultimatum reached the floor. Two of your best people asked me, quietly, whether it’s true we’ll fire Devang to keep the account. They’re not threatening to leave. They just want to know who we are. I didn’t have an answer for them. You do.","from":"people"}'::jsonb, 30, '{"week":3,"from":"people","beat":"surprise","day":4,"kind":"appeal","title":"The floor is asking"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9c70a738-2a47-54a9-b4f3-bc1a0d9305a3', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Ida finds you before you decide: “Whatever you land on with Halloway, I write the statement. So tell me the truth first — are we protecting the principle, or protecting the number? I can sell either one. I just need to know which one I’m actually defending, so I don’t get caught believing the wrong thing at the podium.”","from":"comms"}'::jsonb, 31, '{"week":3,"from":"comms","beat":"pulse"}'::jsonb);
