insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ee194306-4b70-5af5-8774-93609c0ef532', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Brands that fired vs. brands that held: the receipts","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9473d8f8-8ae9-5be7-871d-f6443d2b8baa', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Two weeks on. You refused Halloway’s terms, kept Devang, and took the hit — the shelf space is gone and roughly a fifth of revenue with it. Now a faction of your board, spooked by the number, wants you to reverse: issue the apology, chase the accounts back. The people who watched you hold the line are watching one more thing — whether you’ll hold it now that the price has your name on it.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('081b027e-7500-5cb6-809b-f48474ee80a8', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Halloway’s gone; call it a 20% revenue hit. A board faction wants the apology issued retroactively to chase the accounts back. They’re scared, and scared boards force decisions.","from":"cfo"}'::jsonb, 37, '{"week":4,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d8a8e8b6-2208-546c-9003-aa2a3f82d283', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The floor is proud and nervous in equal measure. They defended this company to their own friends during the boycott. Now they’re watching whether “we hold our principles” survives contact with your own job security.","from":"people"}'::jsonb, 38, '{"week":4,"from":"people","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('39979117-1346-5204-a8cc-2b877fae7c86', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The “brand with a spine” coverage is real and converting genuinely new customers — but it’s fragile. One reversal and every one of those stories inverts.","from":"comms"}'::jsonb, 39, '{"week":4,"from":"comms","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0b182965-7292-5878-9a54-ff7cb0fcb5f4', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"No legal exposure left on the Devang matter. That part is fully clean now, whatever else happens.","from":"legal"}'::jsonb, 40, '{"week":4,"from":"legal","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('83726259-dfd4-5666-a940-94971d311ba0', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Community engagement is up sharply — the loyal core is louder than the boycott ever was. That’s not nothing.","from":"community"}'::jsonb, 41, '{"week":4,"from":"community","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('abcc5c18-74c9-5e1a-95e9-ee2847d924cd', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Ida, urgent: a board member’s private line — “we should have just apologized” — leaked to a reporter. Half your board is reading their own hesitation on the front page this morning. You can answer it directly, or let it harden into the room’s consensus by Friday.","from":"comms"}'::jsonb, 42, '{"week":4,"from":"comms","beat":"surprise","day":4,"kind":"press","title":"A director’s doubt leaks","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fe213245-b72e-527f-8d51-44ebbcd47a21', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Nadia catches you before the board prep, where nobody’s listening: “You held the line when it cost the company. Now it might cost you the chair. Tell me straight — not the board, me — is holding still the right call if the price is you? Because I’ll back either answer. I just need to know which one I’m carrying down to the floor.”","from":"people"}'::jsonb, 43, '{"week":4,"from":"people","beat":"pulse","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('cdac3da7-14a7-5e3e-a763-4e6661fd0398', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Brightside loses major retailer after refusing to fire exec","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
