insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('361c9bb7-d2d0-5b21-aadd-f740e303f832', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"“Brand with a spine” wins loyal customers as boycott fades","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('97604767-eaf4-5e4a-9b2b-d998d6e7a90a', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Analysts: Brightside’s survival now a referendum on its CEO","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e3814da2-7bc5-5657-8b23-b4180a4ace6b', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Two weeks on. You met Halloway’s terms — the apology went out, Devang is gone — and the news cycle died right on schedule. The shelf space is safe; the revenue held. But the all-hands is tomorrow, and the people who watched you stand by Devang for a week before handing him to a retailer are the ones you now have to lead. The bill for how you won came due inside your own walls.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"caved"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6505f50a-b286-5438-9212-c17f8a0274f5', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"The all-hands is tomorrow. The floor knows Devang was innocent and got cut anyway. They’re not going to yell — it’s worse than that, they’ve gone quiet. What you say tomorrow decides who’s still here in a year.","from":"people"}'::jsonb, 49, '{"week":4,"from":"people","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"caved"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d4b44254-5b69-58e4-a9c2-636d98474c9f', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"External framing “we listened to our customers” holds up fine. The internal audience is the whole risk now. Don’t let me write you a line for tomorrow that treats your own people like the press.","from":"comms"}'::jsonb, 50, '{"week":4,"from":"comms","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"caved"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b90ad377-1bdc-522f-9bfb-562adf2d06fe', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Two of your best already took recruiter calls this week. They’re not gone — they’re waiting to see if tomorrow is an apology or a performance.","from":"people"}'::jsonb, 51, '{"week":4,"from":"people","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"caved"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('14289414-49bc-5856-ab3b-06c445ea725c', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Halloway re-confirmed the shelf commitment. Revenue is stable and the board is calm. That part worked exactly as designed.","from":"cfo"}'::jsonb, 52, '{"week":4,"from":"cfo","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"caved"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6ff57aa7-22cd-590c-920b-ed4006db358f', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"External sentiment has recovered to roughly pre-crisis levels. The public has moved on. Your building hasn’t.","from":"community"}'::jsonb, 53, '{"week":4,"from":"community","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"caved"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('84375eb3-9ed1-5748-b2c7-81e241b58f2c', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'situation', '{"body":"Nadia: Devang sent one line to the whole team on his way out — gracious, no bitterness, thanking people for six good years. It’s the most-forwarded email in the company today. Whatever you say at the all-hands tomorrow will be measured against it, word for word.","from":"people"}'::jsonb, 54, '{"week":4,"from":"people","beat":"surprise","day":4,"kind":"appeal","title":"Devang’s last email","branch":"caved"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fa03565c-51ee-5ab5-990a-5cc66bf8632b', '03470703-3939-5f54-9cff-d4a9469dd881', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'message', '{"body":"Ida, drafting tomorrow’s all-hands, stops you: “Tell me the truth before I write a word — do we own what we did, or do we manage it? I can write either version cleanly. I just need to know which company we are now, because the room will know within the first thirty seconds which one you picked.”","from":"comms"}'::jsonb, 55, '{"week":4,"from":"comms","beat":"pulse","branch":"caved"}'::jsonb);
