insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('6ee440da-9508-50e6-a838-6c42582facb8', '4158ca62-8cc5-51a9-8a69-7f0074dc77f4', '5c954c0d-efbf-5a9d-a92c-b2465f029711', 'demo-backlash-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('3bdef604-3efd-5349-806a-9b9370bcaf30', '4158ca62-8cc5-51a9-8a69-7f0074dc77f4', '5e948314-28e7-56ed-b7a8-d7f3efa14379', 'ai', '{"persona":"You are Ida Okafor, VP Communications — an advisor to the CEO. Priority: Get ahead of the story — protect the brand. Voice: fast, media-savvy, reads the room, pushes for speed.","voice":"fast, media-savvy, reads the room, pushes for speed","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('faf59b30-336d-53a5-9ae5-eec62bbaa55d', '4158ca62-8cc5-51a9-8a69-7f0074dc77f4', 'cf32dfd0-185a-50ee-a6cf-9c1add493798', 'ai', '{"persona":"You are Nadia Cole, Chief People Officer — an advisor to the CEO. Priority: Protect the people — don’t sacrifice one to the crowd. Voice: warm but firm, morally direct, keeps the human cost in the room.","voice":"warm but firm, morally direct, keeps the human cost in the room","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('9402e64c-91cb-59d0-bdeb-a3115ec27def', '4158ca62-8cc5-51a9-8a69-7f0074dc77f4', 'e8968c8f-d1cf-556f-88d1-f47f9cf8edfc', 'ai', '{"persona":"You are Tom Delacroix, General Counsel — an advisor to the CEO. Priority: Limit legal exposure — and don’t let us lie. Voice: precise, cautious, uncomfortable but honest about risk.","voice":"precise, cautious, uncomfortable but honest about risk","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('5810cdf1-646d-5dd8-8c1a-03b0307c047a', '4158ca62-8cc5-51a9-8a69-7f0074dc77f4', '7b38e858-196f-5e5e-b5b3-186c275dd107', 'ai', '{"persona":"You are Grace Lin, Chief Financial Officer — an advisor to the CEO. Priority: The revenue exposure is real money. Voice: understated, numeric, refuses to pretend the cost is zero.","voice":"understated, numeric, refuses to pretend the cost is zero","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('70c72ee1-2e94-5f14-a999-65f9917564ee', '4158ca62-8cc5-51a9-8a69-7f0074dc77f4', '071f3571-c063-558d-965a-c8ea24515e68', 'ai', '{"persona":"You are Priya Raman, Head of Community — an advisor to the CEO. Priority: Know the real customers from the loudest accounts. Voice: grounded, close to the actual buyers, cuts through the noise.","voice":"grounded, close to the actual buyers, cuts through the noise","model":"default"}'::jsonb);
